dslRule:
@id: jdt.internal.textblock.jls13-to-jls14
@severity: info
org.eclipse.jdt.core.dom.AST.JLS13_INTERNAL :: sourceVersionGE(14)
=> org.eclipse.jdt.core.dom.AST.JLS14_INTERNAL
;;

@id: jdt.internal.textblock.supportedonlyin13-to-14
@severity: info
supportedOnlyIn13() :: sourceVersionGE(14)
=> supportedOnlyIn14()
;;

/*!id: anon-class-to-method-ref.this*/
/*!description: Converts an anonymous inner class with a single method that delegates to an instance method on 'this' or 'ClassName.this' to a method reference.*/
/*!severity: info*/
new $FunctionalInterface() {
    @java.lang.Override
    public $returnType $methodName($args$) {
        $receiver.$methodName($args$);
    }
} :: sourceVersionGE(8) && (instanceof($receiver, "org.eclipse.jdt.core.dom.ThisExpression") || instanceof($receiver, "org.eclipse.jdt.core.dom.QualifiedThisExpression"))
=> $receiver::$methodName
;;

/*!id: anon-class-to-method-ref.param-void*/
/*!description: Converts an anonymous inner class with a single void method that delegates to an instance method on its parameter, to an instance method reference on the parameter's type.*/
/*!severity: info*/
new $FunctionalInterface() {
    @java.lang.Override
    public void $anonMethodName($paramType $param) {
        $param.$targetMethod();
    }
} :: sourceVersionGE(8)
=> $paramType::$targetMethod
;;

/*!id: anon-class-to-method-ref.param-return*/
/*!description: Converts an anonymous inner class with a single method that returns the result of calling an instance method on its parameter, to an instance method reference on the parameter's type.*/
/*!severity: info*/
new $FunctionalInterface() {
    @java.lang.Override
    public $returnType $anonMethodName($paramType $param) {
        return $param.$targetMethod();
    }
} :: sourceVersionGE(8)
=> $paramType::$targetMethod
;;

/*!id: jdt.internal.formatter.versioner.currentversion.update*/
/*!description: Updates the internal formatter profile version from VERSION_18 to VERSION_19.*/
/*!severity: info*/
org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.CURRENT_VERSION = org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.VERSION_18
=> org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.CURRENT_VERSION = org.eclipse.jdt.internal.ui.preferences.formatter.ProfileVersioner.VERSION_19
;;

